// Write a 'no work' run log when there are no brain dump files to process.
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const log = JSON.stringify({
  workflow: 'brain-dump-processor', run_date: today,
  finished_at: new Date().toISOString(), status: 'no_work',
  files_with_content: 0, tasks_extracted: 0,
  articles_queued: 0, files_processed: []
}, null, 2);
const buf = Buffer.from(log, 'utf-8');
const logKey = `99_System/logs/brain-dump-processor-${today}.json`;
return [{ json: { logKey }, binary: { logFile: { data: buf.toString('base64'), mimeType: 'application/json', fileName: logKey.split('/').pop(), fileExtension: 'json', fileSize: buf.length } } }];

// Read current MTL and append new tasks (with dedup)
const parseOutput = $('Parse & Extract').first().json;
const buildOutput = $('Build Output Files').first().json;
const tasks = parseOutput.tasks || [];
const today = buildOutput.today || parseOutput.today;
const fileName = buildOutput.fileName || parseOutput.fileName;

if (!tasks || tasks.length === 0) {
  return [{ json: { mtlUpdated: false, reason: 'no tasks to append' } }];
}

// Read MTL content from binary
let mtlContent = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  mtlContent = buf.toString('utf-8');
} catch(e) {
  // MTL read failed — still proceed, just can't dedup
  mtlContent = '';
}

// Dedup: extract existing task descriptions
const existing = new Set();
for (const line of mtlContent.split('\n')) {
  const m = line.match(/^- \[[ x]\] (.+?)(?:\s*\[area::|\s*$)/);
  if (m) existing.add(m[1].trim().toLowerCase());
}

const newTasks = tasks.filter(t => {
  const m = t.match(/^- \[ \] (.+?)(?:\s*\[area::|\s*$)/);
  if (!m) return true;
  const desc = m[1].trim().toLowerCase();
  if (existing.has(desc)) return false;
  existing.add(desc);
  return true;
});

if (newTasks.length === 0) {
  return [{ json: { mtlUpdated: false, reason: 'all tasks already in MTL (deduped)' } }];
}

// Append
const appendBlock = `\n\n## Brain Dump Capture — ${today} (${fileName})\n${newTasks.join('\n')}\n`;
const updatedMtl = mtlContent.trimEnd() + appendBlock;
const buf = Buffer.from(updatedMtl, 'utf-8');

return [{ json: {
  mtlUpdated: true, tasksAppended: newTasks.length, totalTasks: tasks.length
}, binary: {
  mtlFile: { data: buf.toString('base64'), mimeType: 'text/markdown; charset=utf-8', fileName: '!!! MASTER TASK LIST.md', fileExtension: 'md', fileSize: buf.length }
}}];
